Tenho esse botão de ação que ficou com toda a lógica no doAction. Preciso refatorar:

```java
public class AprovarAmostraAction implements AcaoRotinaJava {
    @Override
    public void doAction(ContextoAcao ctx) throws Exception {
        if (ctx.getLinhas().length == 0) {
            ctx.setMensagemRetorno("Selecione ao menos uma amostra!");
            return;
        }
        JapeSession.SessionHandle hnd = null;
        try {
            hnd = JapeSession.open();
            for (Registro linha : ctx.getLinhas()) {
                BigDecimal id = BigDecimalUtil.getBigDecimal(linha.getCampo("IDAMOSTRA"));
                DynamicVO vo = JapeFactory.dao("AD_AMOSTRA").findByPK(id);
                if (vo == null) throw new MGEModelException("Amostra não encontrada: " + id);
                if ("A".equals(vo.asString("STATUS"))) throw new MGEModelException("Amostra já aprovada: " + id);
                JapeFactory.dao("AD_AMOSTRA").prepareToUpdateByPK(id)
                    .set("STATUS", "A")
                    .set("DTAPROVACAO", new java.sql.Timestamp(System.currentTimeMillis()))
                    .update();
            }
            ctx.setMensagemRetorno(ctx.getLinhas().length + " amostra(s) aprovada(s).");
        } finally {
            JapeSession.close(hnd);
        }
    }
}
